dslRule:
/*!id: jdt.internal.javadoc.tagproperty.getvalue-to-getstringvalue*/
/*!description: Replace TagProperty.getValue() with TagProperty.getStringValue() to support JEP 413 (DOM AST for Javadoc tags with properties) in JLS18+.*/
/*!severity: info*/
/*!minJavaVersion: 18*/
/*!tags: jdt, internal, refactoring, java18*/
$tagProp.getValue() :: instanceof($tagProp, "org.eclipse.jdt.internal.ui.text.javadoc.JavadocContentAccess2.TagProperty") && sourceVersionGE(18)
=> $tagProp.getStringValue()
;;

